const originalText = Object.fromEntries(
  [...document.querySelectorAll("[data-i18n]")].map((el) => [el.dataset.i18n, el.innerHTML])
);

function updateLocalizedLinks(lang) {
  document.querySelectorAll("a[href]").forEach((link) => {
    const href = link.getAttribute("href");
    if (!href || href.startsWith("#") || href.startsWith("http") || href.startsWith("mailto:") || href.startsWith("tel:")) return;
    if (!href.includes(".html")) return;
    const url = new URL(href, window.location.href);
    url.searchParams.set("lang", lang);
    link.setAttribute("href", `${url.pathname.split("/").pop()}${url.search}${url.hash}`);
  });
}

function localizeSearchUi(lang) {
  const labels = {
    de: {
      button: "Suche",
      label: "Website durchsuchen",
      placeholder: "Website durchsuchen",
      hint: "Suchbegriff eingeben.",
      submit: "Suchen",
    },
    es: {
      button: "Buscar",
      label: "Buscar en la web",
      placeholder: "Buscar en la web",
      hint: "Escriba una palabra para buscar.",
      submit: "Buscar",
    },
    en: {
      button: "Search",
      label: "Search the website",
      placeholder: "Search the website",
      hint: "Enter a search term.",
      submit: "Search",
    },
  }[lang];

  document.querySelectorAll(".site-search").forEach((search) => {
    const button = search.querySelector(".search-toggle");
    const label = search.querySelector("label");
    const input = search.querySelector(".site-search-input");
    const submit = search.querySelector('.site-search-form button[type="submit"]');
    const results = search.querySelector(".search-results");
    if (button) button.textContent = labels.button;
    if (label) label.textContent = labels.label;
    if (input) input.placeholder = labels.placeholder;
    if (submit) submit.setAttribute("aria-label", labels.submit);
    if (results && !results.querySelector(".search-result")) {
      results.innerHTML = `<p>${labels.hint}</p>`;
    }
  });
}

function applyLanguage(lang) {
  const activeLang = ["de", "es", "en"].includes(lang) ? lang : "de";
  if (typeof window.setLanguage === "function") {
    window.setLanguage(activeLang);
  }
  const dict = activeLang === "de" ? originalText : pageTranslations[activeLang];
  document.documentElement.lang = activeLang;
  localStorage.setItem("gss-language", activeLang);
  document.querySelectorAll("[data-i18n]").forEach((el) => {
    const value = dict && dict[el.dataset.i18n];
    if (value) el.innerHTML = value;
  });
  document.querySelectorAll(".lang").forEach((button) => {
    button.classList.toggle("active", button.dataset.lang === activeLang);
  });
  localizeSearchUi(activeLang);
  updateLocalizedLinks(activeLang); if (typeof window.updatePhoneCountryLabels === "function") window.updatePhoneCountryLabels(); if (typeof window.setupFundingPortalLinks === "function") window.setupFundingPortalLinks(); if (typeof window.refreshHumanChecks === "function") window.refreshHumanChecks(); if (typeof window.refreshClientDetails === "function") window.refreshClientDetails(); document.querySelectorAll("#contact-form, #funding-consultation-form").forEach((form) => { if (typeof window.applyLocalizedValidation === "function") window.applyLocalizedValidation(form); });
}

const requestedLanguage = new URLSearchParams(window.location.search).get("lang");
const savedLanguage = localStorage.getItem("gss-language");
applyLanguage(requestedLanguage || savedLanguage || document.documentElement.lang || "de");

document.querySelectorAll(".lang").forEach((button) => {
  button.addEventListener("click", () => applyLanguage(button.dataset.lang));
});


















